                    if count == 0 {
                        Ok(r#"{"verdict": "BLOCKED", "reason": "Testing", "guidance": "Fix it"}"#.to_string())
                    } else {
                        Ok(r#"{"verdict": "ALLOWED", "reason": "Safe", "guidance": "None"}"#.to_string())
                    }
                } else {
                    Ok("Candidate".to_string())
                }
